import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';

const CartPage = () => {
  const { cart, updateQuantity, removeFromCart, getCartTotal } = useCart();
  const { isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const [cartWithProducts, setCartWithProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  // Fetch product details for cart items that don't have populated product data
  useEffect(() => {
    const enrichCartData = async () => {
      setLoading(true);
      try {
        if (!Array.isArray(cart) || cart.length === 0) {
          setCartWithProducts([]);
          setLoading(false);
          return;
        }

        const enriched = await Promise.all(
          cart.map(async (item) => {
            // Check if product is already populated with _id
            if (item?.product?._id) {
              return item;
            }

            // If product is just an ID string, fetch the product details
            const productId = item?.product || item?.productId;
            if (productId && typeof productId === 'string') {
              try {
                const res = await api.get(`/products/${productId}`);
                const product = res.data.data || res.data.product || res.data;
                return {
                  ...item,
                  product
                };
              } catch (err) {
                console.warn(`Failed to fetch product ${productId}:`, err);
                // Return item as-is if fetch fails
                return item;
              }
            }

            return item;
          })
        );

        // Filter out items without valid product data
        const valid = enriched.filter(item => {
          const hasProduct = item?.product?._id || (item?.product && typeof item.product === 'object');
          if (!hasProduct) {
            console.warn('Skipping cart item without product data:', item);
          }
          return hasProduct;
        });

        setCartWithProducts(valid);
      } catch (err) {
        console.error('Error enriching cart data:', err);
        setCartWithProducts(cart);
      } finally {
        setLoading(false);
      }
    };

    enrichCartData();
  }, [cart]);

  const handleCheckout = () => {
    if (!isAuthenticated) {
      navigate('/login');
    } else {
      navigate('/checkout');
    }
  };

  if (loading) {
    return (
      <div className="container text-center" style={{ padding: '60px 20px' }}>
        <div className="loader" style={{ margin: '0 auto' }} />
        <p style={{ marginTop: '20px' }}>Loading cart...</p>
      </div>
    );
  }

  if (!Array.isArray(cartWithProducts) || cartWithProducts.length === 0) {
    return (
      <div className="container text-center">
        <h1>Your Cart is Empty</h1>
        <Link to="/products" className="btn btn-primary mt-3">
          Continue Shopping
        </Link>
      </div>
    );
  }

  return (
    <div className="container">
      <h1>Shopping Cart</h1>
      <div className="cart-content">
        <div className="cart-items">
          {cartWithProducts.map((item, idx) => {
            // Handle both populated and non-populated cart items
            const productObj = item?.product || {};
            const productId = productObj?._id || item?.productId;
            const name = productObj?.name || 'Unknown Product';
            const image = (productObj?.images && productObj.images.length > 0) 
              ? productObj.images[0] 
              : '/placeholder.png';
            const price = Number(productObj?.price) || 0;
            const quantity = Number(item?.quantity) || 0;

            if (!productId) {
              console.warn('Cart item missing productId:', item);
              return null;
            }

            return (
              <div key={productId} className="cart-item">
                <img 
                  src={image} 
                  alt={name}
                  onError={(e) => e.target.src = '/placeholder.png'}
                />
                <div className="cart-item-details">
                  <h3>{name}</h3>
                  <p className="price">₹{price.toLocaleString()}</p>
                  <div className="quantity-controls">
                    <button onClick={() => updateQuantity(productId, quantity - 1)}>-</button>
                    <span>{quantity}</span>
                    <button onClick={() => updateQuantity(productId, quantity + 1)}>+</button>
                  </div>
                </div>
                <div className="cart-item-actions">
                  <p className="subtotal">₹{(price * quantity).toLocaleString()}</p>
                  <button onClick={() => removeFromCart(productId)} className="btn-remove">Remove</button>
                </div>
              </div>
            );
          })}
        </div>
        <div className="cart-summary">
          <h2>Order Summary</h2>
          <div className="summary-row">
            <span>Subtotal:</span>
            <span>₹{getCartTotal().toLocaleString()}</span>
          </div>
          <div className="summary-row">
            <span>Shipping:</span>
            <span>{getCartTotal() >= 500 ? 'FREE' : '₹50'}</span>
          </div>
          <div className="summary-row total">
            <span>Total:</span>
            <span>₹{(getCartTotal() + (getCartTotal() >= 500 ? 0 : 50)).toLocaleString()}</span>
          </div>
          <button onClick={handleCheckout} className="btn btn-primary btn-block">
            Proceed to Checkout
          </button>
        </div>
      </div>
    </div>
  );
};

export default CartPage;
